local LDefenceWarBaseCtrl = LXImport(".LDefenceWarBaseCtrl")

---@class LMatchThreeGameEffPoolCtrl:LDefenceWarBaseCtrl
local LDefenceWarEffPoolCtrl = LxClass("LMatchThreeGameEffPoolCtrl", LDefenceWarBaseCtrl)
-----------------------------------------------------------------

local LxUnity = LxUnity

-----------------------------------------------------------------
function LDefenceWarEffPoolCtrl:LMatchThreeGameEffPoolCtrl()
    -- 特效列表
    self._effMap = {}
end

-- 销毁
function LDefenceWarEffPoolCtrl:OnDestroy()
    -- LxUnity.Destroy(self._nodeParent)

    for _, tab in pairs(self._effMap) do
        tab.dp:Destroy()
    end
    self._effMap = {}
end

-- 获取节点的父节点
function LDefenceWarEffPoolCtrl:GetNodeParent()
    if not self._nodeParent then
        local root = self:GetMap():GetMapTrans()
        local parent = CS.FindTrans(root, "LayerRoot/LayerEff")
        self._nodeParent = parent
    end
    return self._nodeParent
end

-- 获取节点的父节点
function LDefenceWarEffPoolCtrl:GetNodeParentPool()
    if not self._nodeParentPool then
        local root = self:GetMap():GetMapTrans()
        local parent = CS.FindTrans(root, "LayerRoot/LayerEffPool")
        self._nodeParentPool = parent
    end
    return self._nodeParentPool
end

-- 加载一个特效
function LDefenceWarEffPoolCtrl:LoadEffObj(effName, endFunc, param)
    local parent = self:GetNodeParentPool()

    local tab = self._effMap[effName] or {}
    if tab.obj then
        if endFunc then
            endFunc(tab.obj)
        end
        return
    end

    tab.funcList = tab.funcList or {}
    if endFunc then
        table.insert(tab.funcList, endFunc)
    end
    if tab.dp then
        return
    end


    local eff = LDisplayEffect:New()
    eff:CreateEffect(parent, effName)
    eff:SetResTag(CS.RES_TAG_SCENE)
    if param and param.layerName then
        eff:SetRenderLayer(param.layerName)
    end

    tab.dp = eff
    self._effMap[effName] = tab
    eff:SetLoadedFunction(function()
        if self:IsDestroy() then
            eff:Destroy()
            return
        end

        local effTrans = eff:GetDisplayTrans()
        tab.obj = effTrans.gameObject
        for _, func in ipairs(tab.funcList) do
            func(tab.obj)
        end

        local layer = LayerMask.NameToLayer("Object")
        CS.UpdateChildLayer(effTrans, layer)

        -- CS.ShowObject(effTrans, false)
    end)

    eff:StartLoadEffect()
end

return LDefenceWarEffPoolCtrl
